create table charges_financieres (id int primary key NOT NULL, designation varchar(50) NOT NULL UNIQUE, nom_entreprise_fournisseur varchar(50), nom_entreprise_client varchar(50), statut_de_lachat_au_fournisseur int(12), reference varchar(50) UNIQUE, nom_departement_produit varchar(50) NOT NULL, categorie varchar(50) NOT NULL, reference_recu_dachat varchar(50), prix_dachat double NOT NULL, prix_unitaire double NOT NULL, montant_tva double NOT NULL, date_de_commande date NOT NULL, date_de_reception date, localisation varchar(50), quantite_totale double NOT NULL, nom_utilisateur_du_commandeur_de_lachat varchar(256), description_charge_financiere varchar(256));
